INSERT INTO roles (id, name_en, name_ua, description_en, description_ua, type, edition, image_url, meta)
VALUES
  ('acrobat', 'Acrobat', 'Акробат', 'Each night*, if either good living neighbour is drunk or poisoned, you die.', 'Щоночі*, якщо будь-який добрий живий сусід п''яний або отруєний, ви помираєте.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/acrobat.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":44,"otherNightReminder":"If a good living neighbour is drunk or poisoned, the Acrobat player dies.","setup":false,"reminders":["Dead"]}'),
  ('alchemist', 'Alchemist', 'Алхімік', 'You have a not-in-play Minion ability.', 'Ви маєте здатність Міньйона, якого немає у грі.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/alchemist.png', '{"firstNight":4,"firstNightReminder":"Show the Alchemist a not-in-play Minion token","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('alhadikhia', 'Al-Hadikhia', 'Аль-Хадіхія', 'Each night*, choose 3 players (all players learn who): each silently chooses to live or die, but if all live, all die.', 'Щоночі*, оберіть 3 гравців (всі гравці дізнаються хто): кожен мовчки обирає жити чи померти, але якщо всі обирають жити, всі помирають.', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/alhadikhia.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":36,"otherNightReminder":"The Al-Hadikhia chooses 3 players. Announce the first player, wake them to nod yes to live or shake head no to die, kill or resurrect accordingly, then put to sleep and announce the next player. If all 3 are alive after this, all 3 die.","setup":false,"reminders":["1","2","3","Chose death","Chose life"]}'),
  ('amnesiac', 'Amnesiac', 'Амнезіак', 'You do not know what your ability is. Each day, privately guess what it is: you learn how accurate you are.', 'Ви не знаєте, яка у вас здатність. Щодня приватно вгадуйте, яка вона: ви дізнаєтесь, наскільки ви точні.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/amnesiac.png', '{"firstNight":36,"firstNightReminder":"Decide the Amnesiac''s entire ability. If the Amnesiac''s ability causes them to wake tonight: Wake the Amnesiac and run their ability.","otherNight":54,"otherNightReminder":"If the Amnesiac''s ability causes them to wake tonight: Wake the Amnesiac and run their ability.","setup":false,"reminders":["?"]}'),
  ('angel', 'Angel', 'Ангел', 'Something bad might happen to whoever is most responsible for the death of a new player.', 'Щось погане може статися з тим, хто найбільше відповідальний за смерть нового гравця.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/angel.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Protect","Something Bad"]}'),
  ('apprentice', 'Apprentice', 'Учень', 'On your 1st night, you gain a Townsfolk ability (if good), or a Minion ability (if evil).', 'У вашу 1-шу ніч ви отримуєте здатність Городянина (якщо добрий) або Міньйона (якщо злий).', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/apprentice.png', '{"firstNight":null,"firstNightReminder":"Show the Apprentice the ''You are'' card, then a Townsfolk or Minion token. In the Grimoire, replace the Apprentice token with that character token, and put the Apprentice''s ''Is the Apprentice'' reminder by that character token.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Is the Apprentice"]}'),
  ('artist', 'Artist', 'Художник', 'Once per game, during the day, privately ask the Storyteller any yes/no question.', 'Раз за гру, вдень, приватно задайте Оповідачу будь-яке питання так/ні.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/artist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('assassin', 'Assassin', 'Асасін', 'Once per game, at night*, choose a player: they die, even if for some reason they could not.', 'Раз за гру, вночі*, оберіть гравця: він помирає, навіть якщо з якоїсь причини не міг би.', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/assassin.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":41,"otherNightReminder":"If the Assassin has not yet used their ability: The Assassin either shows the ''no'' head signal, or points to a player. That player dies.","setup":false,"reminders":["Dead","No ability"]}'),
  ('atheist', 'Atheist', 'Атеїст', 'The Storyteller can break the game rules & if executed, good wins, even if you are dead. [No evil characters]', 'Оповідач може порушувати правила гри, і якщо його стратять, добро перемагає, навіть якщо ви мертві. [No evil characters]', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/atheist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('balloonist', 'Balloonist', 'Повітроплавець', 'Each night, you learn 1 player of each character type, until there are no more types to learn. [+1 Outsider]', 'Щоночі ви дізнаєтесь 1 гравця кожного типу персонажів, доки не залишиться більше типів. [+1 Outsider]', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/balloonist.png', '{"firstNight":51,"firstNightReminder":"Choose a character type. Point to a player whose character is of that type. Place the Balloonist''s Seen reminder next to that character.","otherNight":69,"otherNightReminder":"Choose a character type that does not yet have a Seen reminder next to a character of that type. Point to a player whose character is of that type, if there are any. Place the Balloonist''s Seen reminder next to that character.","setup":true,"reminders":["Seen Townsfolk","Seen Outsider","Seen Minion","Seen Demon","Seen Traveller"]}'),
  ('banshee', 'Banshee', 'Банші', 'If the Demon kills you, all players learn this. From now on, you may nominate twice per day and vote twice per nomination.', 'Якщо Демон вас вбиває, всі гравці дізнаються про це. Відтепер ви можете номінувати двічі на день і голосувати двічі за номінацію.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/banshee.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":49,"otherNightReminder":"Announce that the Banshee has died.","setup":false,"reminders":["Has Ability"]}'),
  ('barber', 'Barber', 'Цирульник', 'If you died today or tonight, the Demon may choose 2 players (not another Demon) to swap characters.', 'Якщо ви померли сьогодні або цієї ночі, Демон може обрати 2 гравців (не іншого Демона), щоб обміняти їхніх персонажів.', 'outsider', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/barber.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":46,"otherNightReminder":"If the Barber died today: Wake the Demon. Show the ''This character selected you'' card, then Barber token. The Demon either shows a ''no'' head signal, or points to 2 players. If they chose players: Swap the character tokens. Wake each player. Show ''You are'', then their new character token.","setup":false,"reminders":["Haircuts tonight"]}'),
  ('barista', 'Barista', 'Бариста', 'Each night, until dusk, 1) a player becomes sober, healthy and gets true info, or 2) their ability works twice. They learn which.', 'Щоночі, до сутінків, 1) гравець стає тверезим, здоровим і отримує правдиву інформацію, або 2) його здатність спрацьовує двічі. Він дізнається, що саме.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/barista.png', '{"firstNight":null,"firstNightReminder":"Choose a player, wake them and tell them which Barista power is affecting them. Treat them accordingly (sober/healthy/true info or activate their ability twice).","otherNight":null,"otherNightReminder":"Choose a player, wake them and tell them which Barista power is affecting them. Treat them accordingly (sober/healthy/true info or activate their ability twice).","setup":false,"reminders":["Sober & Healthy","Ability twice"]}'),
  ('baron', 'Baron', 'Барон', 'There are extra Outsiders in play. [+2 Outsiders]', 'У грі є додаткові Чужинці. [+2 Outsiders]', 'minion', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/baron.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('beggar', 'Beggar', 'Жебрак', 'You must use a vote token to vote. Dead players may choose to give you theirs. If so, you learn their alignment. You are sober & healthy.', 'Ви повинні використати жетон голосу, щоб голосувати. Мертві гравці можуть віддати вам свій. Якщо так, ви дізнаєтесь їхню сторону. Ви тверезий і здоровий.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/beggar.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bishop', 'Bishop', 'Єпископ', 'Only the Storyteller can nominate. At least 1 opposite player must be nominated each day.', 'Тільки Оповідач може номінувати. Щодня має бути номінований щонайменше 1 гравець протилежної сторони.', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bishop.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Nominate good","Nominate evil"]}'),
  ('bonecollector', 'Bone Collector', 'Збирач Кісток', 'Once per game, at night, choose a dead player: they regain their ability until dusk.', 'Раз за гру, вночі, оберіть мертвого гравця: він відновлює свою здатність до сутінків.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bonecollector.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"The Bone Collector either shakes their head no or points at any dead player. If they pointed at any dead player, put the Bone Collector''s ''Has Ability'' reminder by the chosen player''s character token. (They may need to be woken tonight to use it.)","setup":false,"reminders":["No ability","Has ability"]}'),
  ('boomdandy', 'Boomdandy', 'Бумденді', 'If you are executed, all but 3 players die. 1 minute later, the player with the most players pointing at them dies.', 'Якщо вас стратять, всі, крім 3 гравців, помирають. Через 1 хвилину гравець, на якого вказує найбільше гравців, помирає.', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/boomdandy.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bootlegger', 'Bootlegger', 'Бутлегер', 'This script has homebrew characters or rules.', 'У цьому сценарії є домашні персонажі або правила.', 'fabled', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bootlegger.png', '{"firstNight":null,"firstNightReminder":"Announce the Bootlegger is in play and inform the group of all homebrew characters and/or rules you are using in this game. ","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bountyhunter', 'Bounty Hunter', 'Мисливець за Головами', 'You start knowing 1 evil player. If the player you know dies, you learn another evil player tonight. [1 Townsfolk is evil]', 'На початку ви дізнаєтесь 1 злого гравця. Якщо відомий вам гравець помирає, цієї ночі ви дізнаєтесь іншого злого гравця. [1 Townsfolk is evil]', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bountyhunter.png', '{"firstNight":54,"firstNightReminder":"Point to 1 evil player. Wake the townsfolk who is evil and show them the ''You are'' card and the thumbs down evil sign.","otherNight":72,"otherNightReminder":"If the known evil player has died, point to another evil player. ","setup":true,"reminders":["Known"]}'),
  ('buddhist', 'Buddhist', 'Буддист', 'For the first 2 minutes of each day, veteran players may not talk.', 'Перші 2 хвилини кожного дня досвідчені гравці не можуть розмовляти.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/buddhist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('bureaucrat', 'Bureaucrat', 'Бюрократ', 'Each night, choose a player (not yourself): their vote counts as 3 votes tomorrow.', 'Щоночі оберіть гравця (не себе): його голос завтра рахується як 3 голоси.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/bureaucrat.png', '{"firstNight":null,"firstNightReminder":"The Bureaucrat points to a player. Put the Bureaucrat''s ''3 votes'' reminder by the chosen player''s character token.","otherNight":null,"otherNightReminder":"The Bureaucrat points to a player. Put the Bureaucrat''s ''3 votes'' reminder by the chosen player''s character token.","setup":false,"reminders":["3 votes"]}'),
  ('butcher', 'Butcher', 'М''ясник', 'Each day, after the 1st execution, you may nominate again.', 'Щодня, після 1-ї страти, ви можете номінувати знову.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/butcher.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('butler', 'Butler', 'Дворецький', 'Each night, choose a player (not yourself): tomorrow, you may only vote if they are voting too.', 'Щоночі оберіть гравця (не себе): завтра ви можете голосувати, тільки якщо він теж голосує.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/butler.png', '{"firstNight":43,"firstNightReminder":"The Butler points to a player. Mark that player as ''Master''.","otherNight":75,"otherNightReminder":"The Butler points to a player. Mark that player as ''Master''.","setup":false,"reminders":["Master"]}'),
  ('cannibal', 'Cannibal', 'Канібал', 'You have the ability of the recently killed executee. If they are evil, you are poisoned until a good player dies by execution.', 'Ви маєте здатність нещодавно страченого гравця. Якщо він злий, ви отруєні, доки добрий гравець не помре від страти.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cannibal.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Poisoned","Died today"]}'),
  ('cerenovus', 'Cerenovus', 'Цереновус', 'Each night, choose a player & a good character: they are “mad” they are this character tomorrow, or might be executed.', 'Щоночі оберіть гравця та доброго персонажа: завтра він "божевільний", що є цим персонажем, або може бути страчений.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cerenovus.png', '{"firstNight":28,"firstNightReminder":"The Cerenovus points to a player, then to a character on their sheet. Wake that player. Show the ''This character selected you'' card, then the Cerenovus token. Show the selected character token. If the player is not mad about being that character tomorrow, they can be executed.","otherNight":15,"otherNightReminder":"The Cerenovus points to a player, then to a character on their sheet. Wake that player. Show the ''This character selected you'' card, then the Cerenovus token. Show the selected character token. If the player is not mad about being that character tomorrow, they can be executed.","setup":false,"reminders":["Mad"]}'),
  ('chambermaid', 'Chambermaid', 'Покоївка', 'Each night, choose 2 alive players (not yourself): you learn how many woke tonight due to their ability.', 'Щоночі оберіть 2 живих гравців (не себе): ви дізнаєтесь, скільки з них прокидались цієї ночі завдяки своїй здатності.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/chambermaid.png', '{"firstNight":61,"firstNightReminder":"The Chambermaid points to two players. Show the number signal (0, 1, 2, …) for how many of those players wake tonight for their ability.","otherNight":79,"otherNightReminder":"The Chambermaid points to two players. Show the number signal (0, 1, 2, …) for how many of those players wake tonight for their ability.","setup":false,"reminders":[]}'),
  ('chef', 'Chef', 'Кухар', 'You start knowing how many pairs of evil players there are.', 'На початку ви дізнаєтесь, скільки пар злих гравців є.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/chef.png', '{"firstNight":40,"firstNightReminder":"Show the finger signal (0, 1, 2, …) for the number of pairs of neighbouring evil players.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('choirboy', 'Choirboy', 'Хлопчик з Хору', 'If the Demon kills the King, you learn which player is the Demon. [+ the King]', 'Якщо Демон вбиває Короля, ви дізнаєтесь, який гравець є Демоном. [+ the King]', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/choirboy.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":51,"otherNightReminder":"If the King was killed by the Demon, wake the Choirboy and point to the Demon player.","setup":true,"reminders":[]}'),
  ('clockmaker', 'Clockmaker', 'Годинникар', 'You start knowing how many steps from the Demon to its nearest Minion.', 'На початку ви дізнаєтесь, скільки кроків від Демона до його найближчого Міньйона.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/clockmaker.png', '{"firstNight":45,"firstNightReminder":"Show the hand signal for the number (1, 2, 3, etc.) of places from Demon to closest Minion.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('courtier', 'Courtier', 'Придворний', 'Once per game, at night, choose a character: they are drunk for 3 nights & 3 days.', 'Раз за гру, вночі, оберіть персонажа: він п''яний протягом 3 ночей і 3 днів.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/courtier.png', '{"firstNight":22,"firstNightReminder":"The Courtier either shows a ''no'' head signal, or points to a character on the sheet. If the Courtier used their ability: If that character is in play, that player is drunk.","otherNight":8,"otherNightReminder":"Reduce the remaining number of days the marked player is poisoned. If the Courtier has not yet used their ability: The Courtier either shows a ''no'' head signal, or points to a character on the sheet. If the Courtier used their ability: If that character is in play, that player is drunk.","setup":false,"reminders":["Drunk 3","Drunk 2","Drunk 1","No ability"]}'),
  ('cultleader', 'Cult Leader', 'Лідер Культу', 'Each night, you become the alignment of an alive neighbour. If all good players choose to join your cult, your team wins.', 'Щоночі ви приймаєте сторону живого сусіда. Якщо всі добрі гравці вирішать приєднатися до вашого культу, ваша команда перемагає.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/cultleader.png', '{"firstNight":56,"firstNightReminder":"If the cult leader changed alignment, show them the thumbs up good signal of the thumbs down evil signal accordingly.","otherNight":74,"otherNightReminder":"If the cult leader changed alignment, show them the thumbs up good signal of the thumbs down evil signal accordingly.","setup":false,"reminders":[]}'),
  ('damsel', 'Damsel', 'Панянка', 'All Minions know you are in play. If a Minion publicly guesses you (once), your team loses.', 'Всі Міньйони знають, що ви у грі. Якщо Міньйон публічно вгадає вас (один раз), ваша команда програє.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/damsel.png', '{"firstNight":35,"firstNightReminder":"Wake all the Minions, show them the ''This character selected you'' card and the Damsel token.","otherNight":53,"otherNightReminder":"If selected by the Huntsman, wake the Damsel, show ''You are'' card and a not-in-play Townsfolk token.","setup":false,"reminders":["Guess used"]}'),
  ('deviant', 'Deviant', 'Девіант', 'If you were funny today, you cannot die by exile.', 'Якщо ви були смішним сьогодні, ви не можете померти від вигнання.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/deviant.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('devilsadvocate', 'Devil''s Advocate', 'Адвокат Диявола', 'Each night, choose a living player (different to last night): if executed tomorrow, they don''t die.', 'Щоночі оберіть живого гравця (іншого, ніж минулої ночі): якщо його стратять завтра, він не помирає.', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/devilsadvocate.png', '{"firstNight":25,"firstNightReminder":"The Devil’s Advocate points to a living player. That player survives execution tomorrow.","otherNight":13,"otherNightReminder":"The Devil’s Advocate points to a living player, different from the previous night. That player survives execution tomorrow.","setup":false,"reminders":["Survives execution"]}'),
  ('djinn', 'Djinn', 'Джин', 'Use the Djinn''s special rule. All players know what it is.', 'Використовуйте спеціальне правило Джина. Всі гравці знають, яке воно.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/djinn.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('doomsayer', 'Doomsayer', 'Провісник', 'If 4 or more players live, each living player may publicly choose (once per game) that a player of their own alignment dies.', 'Якщо живих 4 або більше гравців, кожен живий гравець може публічно обрати (раз за гру), щоб гравець його сторони помер.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/doomsayer.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('dreamer', 'Dreamer', 'Сновида', 'Each night, choose a player (not yourself or Travellers): you learn 1 good and 1 evil character, 1 of which is correct.', 'Щоночі оберіть гравця (не себе і не Мандрівників): ви дізнаєтесь 1 доброго та 1 злого персонажа, 1 з яких правильний.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/dreamer.png', '{"firstNight":46,"firstNightReminder":"The Dreamer points to a player. Show 1 good and 1 evil character token; one of these is correct.","otherNight":63,"otherNightReminder":"The Dreamer points to a player. Show 1 good and 1 evil character token; one of these is correct.","setup":false,"reminders":[]}'),
  ('drunk', 'Drunk', 'П''яниця', 'You do not know you are the Drunk. You think you are a Townsfolk character, but you are not.', 'Ви не знаєте, що ви П''яниця. Ви думаєте, що ви Городянин, але це не так.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/drunk.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('duchess', 'Duchess', 'Герцогиня', 'Each day, 3 players may choose to visit you. At night*, each visitor learns how many visitors are evil, but 1 gets false info.', 'Щодня 3 гравці можуть обрати відвідати вас. Вночі* кожен відвідувач дізнається, скільки відвідувачів є злими, але 1 отримує хибну інформацію.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/duchess.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"Wake each player marked “Visitor” or “False Info” one at a time. Show them the Duchess token, then fingers (1, 2, 3) equaling the number of evil players marked “Visitor” or, if you are waking the player marked “False Info,” show them any number of fingers except the number of evil players marked “Visitor.”","setup":false,"reminders":["Visitor","False Info"]}'),
  ('empath', 'Empath', 'Емпат', 'Each night, you learn how many of your 2 alive neighbours are evil.', 'Щоночі ви дізнаєтесь, скільки з ваших 2 живих сусідів є злими.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/empath.png', '{"firstNight":41,"firstNightReminder":"Show the finger signal (0, 1, 2) for the number of evil alive neighbours of the Empath.","otherNight":60,"otherNightReminder":"Show the finger signal (0, 1, 2) for the number of evil neighbours.","setup":false,"reminders":[]}'),
  ('engineer', 'Engineer', 'Інженер', 'Once per game, at night, choose which Minions or which Demon is in play.', 'Раз за гру, вночі, оберіть, які Міньйони або який Демон є у грі.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/engineer.png', '{"firstNight":16,"firstNightReminder":"The Engineer shows a ''no'' head signal, or points to a Demon or points to the relevant number of Minions. If the Engineer chose characters, replace the Demon or Minions with the choices, then wake the relevant players and show them the You are card and the relevant character tokens.","otherNight":5,"otherNightReminder":"The Engineer shows a ''no'' head signal, or points to a Demon or points to the relevant number of Minions. If the Engineer chose characters, replace the Demon or Minions with the choices, then wake the relevant players and show them the ''You are'' card and the relevant character tokens.","setup":false,"reminders":["No ability"]}'),
  ('eviltwin', 'Evil Twin', 'Злий Близнюк', 'You & an opposing player know each other. If the good player is executed, evil wins. Good can''t win if you both live.', 'Ви та гравець протилежної сторони знаєте один одного. Якщо доброго гравця стратять, зло перемагає. Добро не може перемогти, якщо ви обидва живі.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/eviltwin.png', '{"firstNight":26,"firstNightReminder":"Wake the Evil Twin and their twin. Confirm that they have acknowledged each other. Point to the Evil Twin. Show their Evil Twin token to the twin player. Point to the twin. Show their character token to the Evil Twin player.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Twin"]}'),
  ('exorcist', 'Exorcist', 'Екзорцист', 'Each night*, choose a player (different to last night): the Demon, if chosen, learns who you are then doesn''t wake tonight.', 'Щоночі* оберіть гравця (іншого, ніж минулої ночі): Демон, якщо обраний, дізнається хто ви, а потім не прокидається цієї ночі.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/exorcist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":23,"otherNightReminder":"The Exorcist points to a player, different from the previous night. If that player is the Demon: Wake the Demon. Show the Exorcist token. Point to the Exorcist. The Demon does not act tonight.","setup":false,"reminders":["Chosen"]}'),
  ('fanggu', 'Fang Gu', 'Фанг Гу', 'Each night*, choose a player: they die. The 1st Outsider this kills becomes an evil Fang Gu & you die instead. [+1 Outsider]', 'Щоночі* оберіть гравця: він помирає. 1-й Аутсайдер, якого ви так вбиваєте, стає злим Фанг Гу, а ви натомість помираєте. [+1 Outsider]', 'demon', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fanggu.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":31,"otherNightReminder":"The Fang Gu points to a player. That player dies. Or, if that player was an Outsider and there are no other Fang Gu in play: The Fang Gu dies instead of the chosen player. The chosen player is now an evil Fang Gu. Wake the new Fang Gu. Show the ''You are'' card, then the Fang Gu token. Show the ''You are'' card, then the thumb-down ''evil'' hand sign.","setup":true,"reminders":["Dead","Once"]}'),
  ('farmer', 'Farmer', 'Фермер', 'If you die at night, an alive good player becomes a Farmer.', 'Якщо ви помираєте вночі, живий добрий гравець стає Фермером.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/farmer.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":55,"otherNightReminder":"If a Farmer died tonight, choose another good player and make them the Farmer. Wake this player, show them the ''You are'' card and the Farmer character token.","setup":false,"reminders":[]}'),
  ('fearmonger', 'Fearmonger', 'Страхітник', 'Each night, choose a player. If you nominate & execute them, their team loses. All players know if you choose a new player.', 'Щоночі оберіть гравця. Якщо ви номінуєте та стратите його, його команда програє. Всі гравці дізнаються, якщо ви обрали нового гравця.', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fearmonger.png', '{"firstNight":29,"firstNightReminder":"The Fearmonger points to a player. Place the Fear token next to that player and announce that a new player has been selected with the Fearmonger ability.","otherNight":17,"otherNightReminder":"The Fearmonger points to a player. If different from the previous night, place the Fear token next to that player and announce that a new player has been selected with the Fearmonger ability.","setup":false,"reminders":["Fear"]}'),
  ('fibbin', 'Fibbin', 'Фіббін', 'Once per game, 1 good player might get false information.', 'Раз за гру 1 добрий гравець може отримати хибну інформацію.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fibbin.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Used"]}'),
  ('fiddler', 'Fiddler', 'Скрипаль', 'Once per game, the Demon secretly chooses an opposing player: all players choose which of these 2 players win.', 'Раз за гру Демон таємно обирає гравця протилежної сторони: всі гравці обирають, хто з цих 2 гравців перемагає.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fiddler.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('fisherman', 'Fisherman', 'Рибалка', 'Once per game, during the day, visit the Storyteller for some advice to help you win.', 'Раз за гру, вдень, відвідайте Оповідача, щоб отримати пораду для перемоги.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fisherman.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('flowergirl', 'Flowergirl', 'Квіткарка', 'Each night*, you learn if a Demon voted today.', 'Щоночі* ви дізнаєтесь, чи голосував Демон сьогодні.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/flowergirl.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":64,"otherNightReminder":"Nod ''yes'' or shake head ''no'' for whether the Demon voted today. Place the ''Demon not voted'' marker (remove ''Demon voted'', if any).","setup":false,"reminders":["Demon voted","Demon not voted"]}'),
  ('fool', 'Fool', 'Блазень', 'The first time you die, you don''t.', 'Перший раз, коли ви помираєте, ви не помираєте.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fool.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('fortuneteller', 'Fortune Teller', 'Ворожка', 'Each night, choose 2 players: you learn if either is a Demon. There is a good player that registers as a Demon to you.', 'Щоночі оберіть 2 гравців: ви дізнаєтесь, чи є хтось із них Демоном. Є добрий гравець, який реєструється для вас як Демон.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/fortuneteller.png', '{"firstNight":42,"firstNightReminder":"The Fortune Teller points to two players. Give the head signal (nod yes, shake no) for whether one of those players is the Demon. ","otherNight":61,"otherNightReminder":"The Fortune Teller points to two players. Show the head signal (nod ''yes'', shake ''no'') for whether one of those players is the Demon.","setup":false,"reminders":["Red herring"]}'),
  ('gambler', 'Gambler', 'Гравець', 'Each night*, choose a player & guess their character: if you guess wrong, you die.', 'Щоночі* оберіть гравця та вгадайте його персонажа: якщо ви вгадали неправильно, ви помираєте.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/gambler.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":10,"otherNightReminder":"The Gambler points to a player, and a character on their sheet. If incorrect, the Gambler dies.","setup":false,"reminders":["Dead"]}'),
  ('gangster', 'Gangster', 'Гангстер', 'Once per day, you may choose to kill an alive neighbour, if your other alive neighbour agrees.', 'Раз на день ви можете обрати вбити живого сусіда, якщо ваш інший живий сусід погоджується.', 'traveller', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/gangster.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('general', 'General', 'Генерал', 'Each night, you learn which alignment the Storyteller believes is winning: good, evil, or neither.', 'Щоночі ви дізнаєтесь, яка сторона, на думку Оповідача, перемагає: добро, зло чи нічия.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/general.png', '{"firstNight":60,"firstNightReminder":"Show the General thumbs up for good winning, thumbs down for evil winning or thumb to the side for neither.","otherNight":78,"otherNightReminder":"Show the General thumbs up for good winning, thumbs down for evil winning or thumb to the side for neither.","setup":false,"reminders":[]}'),
  ('goblin', 'Goblin', 'Гоблін', 'If you publicly claim to be the Goblin when nominated & are executed that day, your team wins.', 'Якщо ви публічно заявляєте, що ви Гоблін, коли вас номінують, і вас стратять цього дня, ваша команда перемагає.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/goblin.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Claimed"]}'),
  ('godfather', 'Godfather', 'Хрещений Батько', 'You start knowing which Outsiders are in play. If 1 died today, choose a player tonight: they die. [−1 or +1 Outsider]', 'На початку ви дізнаєтесь, які Чужинці є у грі. Якщо 1 помер сьогодні, оберіть гравця цієї ночі: він помирає. [-1 or +1 Outsider]', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/godfather.png', '{"firstNight":24,"firstNightReminder":"Show each of the Outsider tokens in play.","otherNight":42,"otherNightReminder":"If an Outsider died today: The Godfather points to a player. That player dies.","setup":true,"reminders":["Died today","Dead"]}'),
  ('golem', 'Golem', 'Голем', 'You may only nominate once per game. When you do, if the nominee is not the Demon, they die.', 'Ви можете номінувати лише раз за гру. Коли ви це робите, якщо номінований не Демон, він помирає.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/golem.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Can not nominate"]}'),
  ('goon', 'Goon', 'Головоріз', 'Each night, the 1st player to choose you with their ability is drunk until dusk. You become their alignment.', 'Щоночі 1-й гравець, який обирає вас своєю здатністю, стає п''яним до сутінків. Ви приймаєте його сторону.', 'outsider', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/goon.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Drunk"]}'),
  ('gossip', 'Gossip', 'Пліткар', 'Each day, you may make a public statement. Tonight, if it was true, a player dies.', 'Щодня ви можете зробити публічну заяву. Цієї ночі, якщо вона була правдивою, гравець помирає.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/gossip.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":43,"otherNightReminder":"If the Gossip’s public statement was true: Choose a player not protected from dying tonight. That player dies.","setup":false,"reminders":["Dead"]}'),
  ('grandmother', 'Grandmother', 'Бабуся', 'You start knowing a good player & their character. If the Demon kills them, you die too.', 'На початку ви дізнаєтесь доброго гравця та його персонажа. Якщо Демон його вбиває, ви теж помираєте.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/grandmother.png', '{"firstNight":44,"firstNightReminder":"Show the marked character token. Point to the marked player.","otherNight":58,"otherNightReminder":"If the Grandmother’s grandchild was killed by the Demon tonight: The Grandmother dies.","setup":false,"reminders":["Grandchild"]}'),
  ('gunslinger', 'Gunslinger', 'Стрілець', 'Each day, after the 1st vote has been tallied, you may choose a player that voted: they die.', 'Щодня, після підрахунку 1-го голосування, ви можете обрати гравця, який голосував: він помирає.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/gunslinger.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('harlot', 'Harlot', 'Гетера', 'Each night*, choose a living player: if they agree, you learn their character, but you both might die.', 'Щоночі* оберіть живого гравця: якщо він погоджується, ви дізнаєтесь його персонажа, але ви обидва можете померти.', 'traveller', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/harlot.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"The Harlot points at any player. Then, put the Harlot to sleep. Wake the chosen player, show them the ''This character selected you'' token, then the Harlot token. That player either nods their head yes or shakes their head no. If they nodded their head yes, wake the Harlot and show them the chosen player''s character token. Then, you may decide that both players die.","setup":false,"reminders":["Dead"]}'),
  ('harpy', 'Harpy', 'Гарпія', 'Each night, choose 2 players: tomorrow, the 1st player is mad that the 2nd is evil, or both might die.', 'Щоночі оберіть 2 гравців: завтра 1-й гравець "божевільний", що 2-й є злим, або обидва можуть померти.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/harpy.png', '{"firstNight":30,"firstNightReminder":"Wake the Harpy; they point at one player, then another. Wake the 1st player the Harpy pointed to, show them the ''This character has selected you'' card, show them the Harpy token, then point at the 2nd player the Harpy pointed to.","otherNight":18,"otherNightReminder":"Wake the Harpy; they point at one player, then another. Wake the 1st player the Harpy pointed to, show them the ''This character has selected you'' card, show them the Harpy token, then point at the 2nd player the Harpy pointed to.","setup":false,"reminders":["Mad","2nd"]}'),
  ('hatter', 'Hatter', 'Капелюшник', 'If you died today or tonight, the Minion & Demon players may choose new Minion & Demon characters to be.', 'Якщо ви померли сьогодні або цієї ночі, гравці-Міньйони та гравець-Демон можуть обрати нових персонажів Міньйонів та Демона.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/hatter.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":45,"otherNightReminder":"If the Hatter died today: Wake the Minions and Demon. Show them the ''This Character Selected You'' info token, then the Hatter token. Each player either shakes their head no or points to another character of the same type as their current character.  If a second player would end up with the same character as another player, shake your head no and gesture for them to choose again. Put them to sleep. Change each player to the character they chose.","setup":false,"reminders":["Tea Party Tonight"]}'),
  ('hellslibrarian', 'Hell''s Librarian', 'Бібліотекар Пекла', 'Something bad might happen to whoever talks when the Storyteller has asked for silence.', 'Щось погане може статися з тим, хто розмовляє, коли Оповідач попросив тишу.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/hellslibrarian.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Something Bad"]}'),
  ('heretic', 'Heretic', 'Єретик', 'Whoever wins, loses & whoever loses, wins, even if you are dead.', 'Хто перемагає — програє, а хто програє — перемагає, навіть якщо ви мертві.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/heretic.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('highpriestess', 'High Priestess', 'Верховна Жриця', 'Each night, learn which player the Storyteller believes you should talk to most.', 'Щоночі ви дізнаєтесь, з яким гравцем Оповідач вважає вам найбільш потрібно поговорити.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/highpriestess.png', '{"firstNight":59,"firstNightReminder":"Point to a player.","otherNight":77,"otherNightReminder":"Point to a player.","setup":false,"reminders":[]}'),
  ('huntsman', 'Huntsman', 'Єгер', 'Once per game, at night, choose a living player: the Damsel, if chosen, becomes a not-in-play Townsfolk. [+the Damsel]', 'Раз за гру, вночі, оберіть живого гравця: Панянка, якщо обрана, стає Городянином, якого немає у грі. [+ the Damsel]', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/huntsman.png', '{"firstNight":34,"firstNightReminder":"The Huntsman shakes their head ''no'' or points to a player. If they point to the Damsel, wake that player, show the ''You are'' card and a not-in-play character token.","otherNight":52,"otherNightReminder":"The Huntsman shakes their head ''no'' or points to a player. If they point to the Damsel, wake that player, show the ''You are'' card and a not-in-play character token.","setup":true,"reminders":["No ability"]}'),
  ('imp', 'Imp', 'Імп', 'Each night*, choose a player: they die. If you kill yourself this way, a Minion becomes the Imp.', 'Щоночі* оберіть гравця: він помирає. Якщо ви вбиваєте себе таким чином, Міньйон стає Імпом.', 'demon', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/imp.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":26,"otherNightReminder":"The Imp points to a player. That player dies. If the Imp chose themselves: Replace the character of 1 alive minion with a spare Imp token. Show the ''You are'' card, then the Imp token.","setup":false,"reminders":["Dead"]}'),
  ('innkeeper', 'Innkeeper', 'Шинкар', 'Each night*, choose 2 players: they can''t die tonight, but 1 is drunk until dusk.', 'Щоночі* оберіть 2 гравців: вони не можуть померти цієї ночі, але 1 з них п''яний до сутінків.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/innkeeper.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":9,"otherNightReminder":"The previously protected and drunk players lose those markers. The Innkeeper points to two players. Those players are protected. One is drunk.","setup":false,"reminders":["Protected","Drunk"]}'),
  ('investigator', 'Investigator', 'Слідчий', 'You start knowing that 1 of 2 players is a particular Minion.', 'На початку ви дізнаєтесь, що 1 з 2 гравців є певним Міньйоном.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/investigator.png', '{"firstNight":39,"firstNightReminder":"Show the character token of a Minion in play. Point to two players, one of which is that character.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Minion","Wrong"]}'),
  ('judge', 'Judge', 'Суддя', 'Once per game, if another player nominated, you may choose to force the current execution to pass or fail.', 'Раз за гру, якщо інший гравець номінував, ви можете примусити поточну страту відбутися або не відбутися.', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/judge.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('juggler', 'Juggler', 'Жонглер', 'On your 1st day, publicly guess up to 5 players'' characters. That night, you learn how many you got correct.', 'У ваш 1-й день публічно вгадайте персонажів до 5 гравців. Цієї ночі ви дізнаєтесь, скільки ви вгадали правильно.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/juggler.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":68,"otherNightReminder":"If today was the Juggler’s first day: Show the hand signal for the number (0, 1, 2, etc.) of ''Correct'' markers. Remove markers.","setup":false,"reminders":["Correct"]}'),
  ('kazali', 'Kazali', 'Казалі', 'Each night*, choose a player: they die. [You choose which players are Minions. -? to +? Outsiders]', 'Щоночі* оберіть гравця: він помирає. [You choose which players are Minions. -? to +? Outsiders]', 'demon', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/kazali.png', '{"firstNight":3,"firstNightReminder":"The Kazali points to a player and a Minion on the character sheet. They do this for as many Minions as should be in play. Change those players'' tokens to the chosen Minion tokens in the Grim. Wake those players, show them the ''You Are'' card, the Minions they have become, and a thumbs down.","otherNight":40,"otherNightReminder":"The Kazali points to a player. That player dies","setup":true,"reminders":["Dead"]}'),
  ('king', 'King', 'Король', 'Each night, if the dead outnumber the living, you learn 1 alive character. The Demon knows who you are.', 'Щоночі, якщо мертвих більше, ніж живих, ви дізнаєтесь 1 живого персонажа. Демон знає, хто ви.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/king.png', '{"firstNight":13,"firstNightReminder":"Wake the Demon, show them the ''This character selected you'' card, show the King token and point to the King player.","otherNight":71,"otherNightReminder":"If there are more dead than living, show the King a character token of a living player.","setup":false,"reminders":[]}'),
  ('klutz', 'Klutz', 'Незграба', 'When you learn that you died, publicly choose 1 alive player: if they are evil, your team loses.', 'Коли ви дізнаєтесь, що померли, публічно оберіть 1 живого гравця: якщо він злий, ваша команда програє.', 'outsider', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/klutz.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('knight', 'Knight', 'Лицар', 'You start knowing 2 players that are not the Demon.', 'На початку ви дізнаєтесь 2 гравців, які не є Демоном.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/knight.png', '{"firstNight":49,"firstNightReminder":"Point to two players who are not the Demon.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Knows"]}'),
  ('legion', 'Legion', 'Легіон', 'Each night*, a player might die. Executions fail if only evil voted. You register as a Minion too. [Most players are Legion]', 'Щоночі* гравець може померти. Страти не вдаються, якщо голосували тільки злі. Ви також реєструєтесь як Міньйон. [Most players are Legion]', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/legion.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":25,"otherNightReminder":"Choose a player, that player dies.","setup":true,"reminders":["Dead","About to die"]}'),
  ('leviathan', 'Leviathan', 'Левіафан', 'If more than 1 good player is executed, you win. All players know you are in play. After day 5, evil wins.', 'Якщо страчено більше 1 доброго гравця, ви перемагаєте. Всі гравці знають, що ви у грі. Після 5-го дня зло перемагає.', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/leviathan.png', '{"firstNight":64,"firstNightReminder":"Place the Leviathan ''Day 1'' marker. Announce ''The Leviathan is in play; this is Day 1.''","otherNight":82,"otherNightReminder":"Change the Leviathan Day reminder for the next day.","setup":false,"reminders":["Day 1","Day 2","Day 3","Day 4","Day 5","Good player executed"]}'),
  ('librarian', 'Librarian', 'Бібліотекарка', 'You start knowing that 1 of 2 players is a particular Outsider. (Or that zero are in play.)', 'На початку ви дізнаєтесь, що 1 з 2 гравців є певним Аутсайдером. (Або що їх немає у грі.)', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/librarian.png', '{"firstNight":38,"firstNightReminder":"Show the character token of an Outsider in play. Point to two players, one of which is that character.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Outsider","Wrong"]}'),
  ('lilmonsta', 'Lil'' Monsta', 'Малий Монстр', 'Each night, Minions choose who babysits Lil'' Monsta''s token & "is the Demon". A player dies each night*. [+1 Minion]', 'Щоночі Міньйони обирають, хто доглядає жетон Малого Монстра та "є Демоном". Щоночі* гравець помирає. [+1 Minion]', 'demon', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lilmonsta.png', '{"firstNight":18,"firstNightReminder":"Wake all Minions together, allow them to vote by pointing at who they want to babysit Lil'' Monsta.","otherNight":38,"otherNightReminder":"Wake all Minions together, allow them to vote by pointing at who they want to babysit Lil'' Monsta. Choose a player, that player dies.","setup":true,"reminders":[]}'),
  ('lleech', 'Lleech', 'Ллеч', 'Each night*, choose a player: they die. You start by choosing an alive player: they are poisoned - you die if & only if they die.', 'Щоночі* оберіть гравця: він помирає. На початку оберіть живого гравця: він отруєний — ви помираєте тоді й тільки тоді, коли він помирає.', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lleech.png', '{"firstNight":19,"firstNightReminder":"The Lleech points to a player. Place the Poisoned reminder token.","otherNight":37,"otherNightReminder":"The Lleech points to a player. That player dies.","setup":false,"reminders":["Dead","Poisoned"]}'),
  ('lunatic', 'Lunatic', 'Божевільний', 'You think you are a Demon, but you are not. The Demon knows who you are & who you choose at night.', 'Ви думаєте, що ви Демон, але це не так. Демон знає, хто ви і кого ви обираєте вночі.', 'outsider', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lunatic.png', '{"firstNight":10,"firstNightReminder":"If 7 or more players: Show the Lunatic a number of arbitrary ''Minions'', players equal to the number of Minions in play. Show 3 character tokens of arbitrary good characters. If the token received by the Lunatic is a Demon that would wake tonight: Allow the Lunatic to do the Demon actions. Place their ''attack'' markers. Wake the Demon. Show the Demon’s real character token. Show them the Lunatic player. If the Lunatic attacked players: Show the real demon each marked player. Remove any Lunatic ''attack'' markers.","otherNight":22,"otherNightReminder":"Allow the Lunatic to do the actions of the Demon. Place their ''attack'' markers. If the Lunatic selected players: Wake the Demon. Show the ''attack'' marker, then point to each marked player. Remove any Lunatic ''attack'' markers.","setup":false,"reminders":["Attack 1","Attack 2","Attack 3"]}'),
  ('lycanthrope', 'Lycanthrope', 'Лікантроп', 'Each night*, choose a living player: if good, they die, but they are the only player that can die tonight.', 'Щоночі* оберіть живого гравця: якщо він добрий, він помирає, але він єдиний гравець, який може померти цієї ночі.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/lycanthrope.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":24,"otherNightReminder":"The Lycanthrope points to a living player: if good, they die and no one else can die tonight.","setup":false,"reminders":["Dead"]}'),
  ('magician', 'Magician', 'Маг', 'The Demon thinks you are a Minion. Minions think you are a Demon.', 'Демон думає, що ви Міньйон. Міньйони думають, що ви Демон.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/magician.png', '{"firstNight":7,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('marionette', 'Marionette', 'Маріонетка', 'You think you are a good character but you are not. The Demon knows who you are. [You neighbour the Demon]', 'Ви думаєте, що ви добрий персонаж, але це не так. Демон знає, хто ви. [You neighbour the Demon]', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/marionette.png', '{"firstNight":15,"firstNightReminder":"Select one of the good players next to the Demon and place the Is the Marionette reminder token. Wake the Demon and show them the Marionette.","otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('mastermind', 'Mastermind', 'Маестро Зла', 'If the Demon dies by execution (ending the game), play for 1 more day. If a player is then executed, their team loses.', 'Якщо Демон помирає від страти (завершуючи гру), гра триває ще 1 день. Якщо потім гравця стратять, його команда програє.', 'minion', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mastermind.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('mathematician', 'Mathematician', 'Математик', 'Each night, you learn how many players’ abilities worked abnormally (since dawn) due to another character''s ability.', 'Щоночі ви дізнаєтесь, скільки здатностей гравців спрацювали аномально (з світанку) через здатність іншого персонажа.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mathematician.png', '{"firstNight":62,"firstNightReminder":"Show the hand signal for the number (0, 1, 2, etc.) of players whose ability malfunctioned due to other abilities.","otherNight":80,"otherNightReminder":"Show the hand signal for the number (0, 1, 2, etc.) of players whose ability malfunctioned due to other abilities.","setup":false,"reminders":["Abnormal"]}'),
  ('matron', 'Matron', 'Матрона', 'Each day, you may choose up to 3 sets of 2 players to swap seats. Players may not leave their seats to talk in private.', 'Щодня ви можете обрати до 3 пар гравців, щоб обміняти їх місцями. Гравці не можуть залишати свої місця для приватних розмов.', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/matron.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('mayor', 'Mayor', 'Мер', 'If only 3 players live & no execution occurs, your team wins. If you die at night, another player might die instead.', 'Якщо залишилось лише 3 живих гравці і страти не відбувається, ваша команда перемагає. Якщо ви помираєте вночі, інший гравець може померти натомість.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mayor.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('mephit', 'Mephit', 'Мефіт', 'You start knowing a secret word. The 1st good player to say this word becomes evil that night.', 'На початку ви дізнаєтесь таємне слово. 1-й добрий гравець, який скаже це слово, стає злим цієї ночі.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mephit.png', '{"firstNight":null,"firstNightReminder":"Show the Mephit their secret word.","otherNight":null,"otherNightReminder":"Wake the 1st good player that said the Mephit''s secret word and show them the ''You are'' card and the thumbs down evil signal.","setup":false,"reminders":["Turns evil","No ability"]}'),
  ('mezepheles', 'Mezepheles', 'Мезефелес', 'You start knowing a secret word. The 1st good player to say this word becomes evil that night.', 'На початку ви дізнаєтесь таємне слово. 1-й добрий гравець, який скаже це слово, стає злим цієї ночі.', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mezepheles.png', '{"firstNight":31,"firstNightReminder":"Show the Mezepheles their secret word.","otherNight":19,"otherNightReminder":"Wake the 1st good player that said the Mezepheles'' secret word and show them the ''You are'' card and the thumbs down evil signal.","setup":false,"reminders":["Turns evil","No ability"]}'),
  ('minstrel', 'Minstrel', 'Менестрель', 'When a Minion dies by execution, all other players (except Travellers) are drunk until dusk tomorrow.', 'Коли Міньйон помирає від страти, всі інші гравці (крім Мандрівників) п''яні до сутінків наступного дня.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/minstrel.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Everyone drunk"]}'),
  ('monk', 'Monk', 'Монах', 'Each night*, choose a player (not yourself): they are safe from the Demon tonight.', 'Щоночі* оберіть гравця (не себе): він захищений від Демона цієї ночі.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/monk.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":12,"otherNightReminder":"The previously protected player is no longer protected. The Monk points to a player not themself. Mark that player ''Protected''.","setup":false,"reminders":["Protected"]}'),
  ('moonchild', 'Moonchild', 'Дитя Місяця', 'When you learn that you died, publicly choose 1 alive player. Tonight, if it was a good player, they die.', 'Коли ви дізнаєтесь, що померли, публічно оберіть 1 живого гравця. Цієї ночі, якщо це був добрий гравець, він помирає.', 'outsider', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/moonchild.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":57,"otherNightReminder":"If the Moonchild used their ability to target a player today: If that player is good, they die.","setup":false,"reminders":["Dead"]}'),
  ('mutant', 'Mutant', 'Мутант', 'If you are “mad” about being an Outsider, you might be executed.', 'Якщо ви "божевільний", що ви Аутсайдер, вас можуть стратити.', 'outsider', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/mutant.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('nightwatchman', 'Nightwatchman', 'Нічний Вартовий', 'Once per game, at night, choose a player: they learn who you are.', 'Раз за гру, вночі, оберіть гравця: він дізнається, хто ви.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/nightwatchman.png', '{"firstNight":55,"firstNightReminder":"The Nightwatchman may point to a player. Wake that player, show the ''This character selected you'' card and the Nightwatchman token, then point to the Nightwatchman player.","otherNight":73,"otherNightReminder":"The Nightwatchman may point to a player. Wake that player, show the ''This character selected you'' card and the Nightwatchman token, then point to the Nightwatchman player.","setup":false,"reminders":["No ability"]}'),
  ('noble', 'Noble', 'Шляхтич', 'You start knowing 3 players, 1 and only 1 of which is evil.', 'На початку ви дізнаєтесь 3 гравців, рівно 1 з яких є злим.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/noble.png', '{"firstNight":50,"firstNightReminder":"Point to 3 players including one evil player, in no particular order.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Seen"]}'),
  ('nodashii', 'No Dashii', 'Но Даші', 'Each night*, choose a player: they die. Your 2 Townsfolk neighbours are poisoned.', 'Щоночі* оберіть гравця: він помирає. Ваші 2 сусіди-Городяни отруєні.', 'demon', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/nodashii.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":32,"otherNightReminder":"The No Dashii points to a player. That player dies.","setup":false,"reminders":["Dead","Poisoned"]}'),
  ('ogre', 'Ogre', 'Огр', 'On your 1st night, choose a player (not yourself): you become their alignment (you don''t know which) even if drunk or poisoned.', 'У вашу 1-шу ніч оберіть гравця (не себе): ви приймаєте його сторону (ви не знаєте яку), навіть якщо п''яний або отруєний.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/ogre.png', '{"firstNight":58,"firstNightReminder":"The Ogre points to a player (not themselves) and becomes their alignment.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('ojo', 'Ojo', 'Оджо', 'Each night*, choose a character: they die. If they are not in play, the Storyteller chooses who dies.', 'Щоночі* оберіть персонажа: він помирає. Якщо його немає у грі, Оповідач обирає, хто помирає.', 'demon', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/ojo.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":35,"otherNightReminder":"The Ojo points to a character on the sheet; if in play, that player dies. If it is not in play, the Storyteller chooses who dies instead.","setup":false,"reminders":["Dead"]}'),
  ('oracle', 'Oracle', 'Оракул', 'Each night*, you learn how many dead players are evil.', 'Щоночі* ви дізнаєтесь, скільки мертвих гравців є злими.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/oracle.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":66,"otherNightReminder":"Show the hand signal for the number (0, 1, 2, etc.) of dead evil players.","setup":false,"reminders":[]}'),
  ('organgrinder', 'Organ Grinder', 'Шарманщик', 'All players keep their eyes closed when voting & the vote tally is secret. Votes for you only count if you vote.', 'Всі гравці тримають очі закритими під час голосування, і підрахунок голосів таємний. Голоси за вас рахуються, тільки якщо ви голосуєте.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/organgrinder.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["About to die"]}'),
  ('pacifist', 'Pacifist', 'Пацифіст', 'Executed good players might not die.', 'Страчені добрі гравці можуть не померти.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/pacifist.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('philosopher', 'Philosopher', 'Філософ', 'Once per game, at night, choose a good character: gain that ability. If this character is in play, they are drunk.', 'Раз за гру, вночі, оберіть доброго персонажа: ви отримуєте його здатність. Якщо цей персонаж у грі, він стає п''яним.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/philosopher.png', '{"firstNight":2,"firstNightReminder":"The Philosopher either shows a ''no'' head signal, or points to a good character on their sheet. If they chose a character: Swap the out-of-play character token with the Philosopher token and add the ''Is the Philosopher'' reminder. If the character is in play, place the drunk marker by that player.","otherNight":2,"otherNightReminder":"If the Philosopher has not used their ability: the Philosopher either shows a ''no'' head signal, or points to a good character on their sheet. If they chose a character: Swap the out-of-play character token with the Philosopher token and add the ''Is the Philosopher'' reminder. If the character is in play, place the drunk marker by that player.","setup":false,"reminders":["Drunk","Is the Philosopher"]}'),
  ('pithag', 'Pit-Hag', 'Піт-Хаг', 'Each night*, choose a player & a character they become (if not-in-play). If a Demon is made, deaths tonight are arbitrary.', 'Щоночі* оберіть гравця та персонажа, яким він стане (якщо його немає у грі). Якщо створено Демона, смерті цієї ночі довільні.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/pithag.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":16,"otherNightReminder":"The Pit-Hag points to a player and a character on the sheet. If this character is not in play, wake that player and show them the ''You are'' card and the relevant character token. If the character is in play, nothing happens.","setup":false,"reminders":[]}'),
  ('pixie', 'Pixie', 'Піксі', 'You start knowing 1 in-play Townsfolk. If you were mad that you were this character, you gain their ability when they die.', 'На початку ви дізнаєтесь 1 Городянина у грі. Якщо ви були "божевільні", що є цим персонажем, ви отримуєте його здатність, коли він помирає.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/pixie.png', '{"firstNight":33,"firstNightReminder":"Show the Pixie 1 in-play Townsfolk character token.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Mad","Has ability"]}'),
  ('plaguedoctor', 'Plague Doctor', 'Чумний Лікар', 'If you die, the Storyteller gains a not-in-play Minion ability.', 'Якщо ви помираєте, Оповідач отримує здатність Міньйона, якого немає у грі.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/plaguedoctor.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Storyteller Ability"]}'),
  ('po', 'Po', 'По', 'Each night*, you may choose a player: they die. If your last choice was no-one, choose 3 players tonight.', 'Щоночі* ви можете обрати гравця: він помирає. Якщо минулої ночі ви нікого не обрали, оберіть 3 гравців цієї ночі.', 'demon', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/po.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":30,"otherNightReminder":"If the Po chose no-one the previous night: The Po points to three players. Otherwise: The Po either shows the ''no'' head signal , or points to a player. Chosen players die","setup":false,"reminders":["Dead","3 attacks"]}'),
  ('poisoner', 'Poisoner', 'Отруювач', 'Each night, choose a player: they are poisoned tonight and tomorrow day.', 'Щоночі оберіть гравця: він отруєний цієї ночі та завтрашнього дня.', 'minion', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/poisoner.png', '{"firstNight":20,"firstNightReminder":"The Poisoner points to a player. That player is poisoned.","otherNight":7,"otherNightReminder":"The previously poisoned player is no longer poisoned. The Poisoner points to a player. That player is poisoned.","setup":false,"reminders":["Poisoned"]}'),
  ('politician', 'Politician', 'Політик', 'If you were the player most responsible for your team losing, you change alignment & win, even if dead.', 'Якщо ви були гравцем, найбільш відповідальним за програш вашої команди, ви змінюєте сторону та перемагаєте, навіть якщо мертві.', 'outsider', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/politician.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('poppygrower', 'Poppy Grower', 'Маковод', 'Minions & Demons do not know each other. If you die, they learn who each other are that night.', 'Міньйони та Демони не знають один одного. Якщо ви помираєте, вони дізнаються, хто є хто, цієї ночі.', 'townsfolk', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/poppygrower.png', '{"firstNight":5,"firstNightReminder":"Do not inform the Demon/Minions who each other are","otherNight":3,"otherNightReminder":"If the Poppy Grower has died, show the Minions/Demon who each other are.","setup":false,"reminders":["Evil wakes"]}'),
  ('preacher', 'Preacher', 'Проповідник', 'Each night, choose a player: a Minion, if chosen, learns this. All chosen Minions have no ability.', 'Щоночі оберіть гравця: Міньйон, якщо обраний, дізнається про це. Всі обрані Міньйони не мають здатності.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/preacher.png', '{"firstNight":17,"firstNightReminder":"The Preacher chooses a player. If a Minion is chosen, wake the Minion and show the ''This character selected you'' card and then the Preacher token.","otherNight":6,"otherNightReminder":"The Preacher chooses a player. If a Minion is chosen, wake the Minion and show the ''This character selected you'' card and then the Preacher token.","setup":false,"reminders":["At a sermon"]}'),
  ('professor', 'Professor', 'Професор', 'Once per game, at night*, choose a dead player: if they are a Townsfolk, they are resurrected.', 'Раз за гру, вночі*, оберіть мертвого гравця: якщо він Городянин, він воскресає.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/professor.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":50,"otherNightReminder":"If the Professor has not used their ability: The Professor either shakes their head no, or points to a player. If that player is a Townsfolk, they are now alive.","setup":false,"reminders":["Alive","No ability"]}'),
  ('psychopath', 'Psychopath', 'Психопат', 'Each day, before nominations, you may publicly choose a player: they die. If executed, you only die if you lose roshambo.', 'Щодня, перед номінаціями, ви можете публічно обрати гравця: він помирає. Якщо вас стратять, ви помираєте лише якщо програєте в "камінь-ножиці-папір".', 'minion', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/psychopath.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('pukka', 'Pukka', 'Пукка', 'Each night, choose a player: they are poisoned. The previously poisoned player dies then becomes healthy.', 'Щоночі оберіть гравця: він отруєний. Раніше отруєний гравець помирає і стає здоровим.', 'demon', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/pukka.png', '{"firstNight":32,"firstNightReminder":"The Pukka points to a player. That player is poisoned.","otherNight":28,"otherNightReminder":"The Pukka points to a player. That player is poisoned. The previously poisoned player dies. ","setup":false,"reminders":["Poisoned","Dead"]}'),
  ('puzzlemaster', 'Puzzlemaster', 'Майстер Загадок', '1 player is drunk, even if you die. If you guess (once) who it is, learn the Demon player, but guess wrong & get false info.', '1 гравець п''яний, навіть якщо ви помираєте. Якщо ви вгадаєте (один раз), хто це, ви дізнаєтесь гравця-Демона, але якщо вгадаєте неправильно — отримаєте хибну інформацію.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/puzzlemaster.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Drunk","Guess used"]}'),
  ('ravenkeeper', 'Ravenkeeper', 'Хранитель Воронів', 'If you die at night, you are woken to choose a player: you learn their character.', 'Якщо ви помираєте вночі, вас будять, щоб обрати гравця: ви дізнаєтесь його персонажа.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/ravenkeeper.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":59,"otherNightReminder":"If the Ravenkeeper died tonight: The Ravenkeeper points to a player. Show that player’s character token.","setup":false,"reminders":[]}'),
  ('recluse', 'Recluse', 'Відлюдник', 'You might register as evil & as a Minion or Demon, even if dead.', 'Ви можете реєструватися як злий та як Міньйон або Демон, навіть якщо мертві.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/recluse.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('revolutionary', 'Revolutionary', 'Революціонер', '2 neighboring players are known to be the same alignment. Once per game, one of them registers falsely.', '2 сусідніх гравці відомі як гравці однієї сторони. Раз за гру один з них реєструється хибно.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/revolutionary.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Used"]}'),
  ('riot', 'Riot', 'Бунт', 'Nominees die, but may nominate again immediately (on day 3, they must). After day 3, evil wins. [All Minions are Riot]', 'Номіновані помирають, але можуть номінувати знову негайно (на 3-й день вони мусять). Після 3-го дня зло перемагає. [All Minions are Riot]', 'demon', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/riot.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('sage', 'Sage', 'Мудрець', 'If the Demon kills you, you learn that it is 1 of 2 players.', 'Якщо Демон вас вбиває, ви дізнаєтесь, що це 1 з 2 гравців.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/sage.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":48,"otherNightReminder":"If the Sage was killed by a Demon: Point to two players, one of which is that Demon.","setup":false,"reminders":[]}'),
  ('sailor', 'Sailor', 'Моряк', 'Each night, choose an alive player: either you or they are drunk until dusk. You can''t die.', 'Щоночі оберіть живого гравця: або ви, або він п''яний до сутінків. Ви не можете померти.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/sailor.png', '{"firstNight":14,"firstNightReminder":"The Sailor points to a living player. Either the Sailor, or the chosen player, is drunk.","otherNight":4,"otherNightReminder":"The previously drunk player is no longer drunk. The Sailor points to a living player. Either the Sailor, or the chosen player, is drunk.","setup":false,"reminders":["Drunk"]}'),
  ('saint', 'Saint', 'Святий', 'If you die by execution, your team loses.', 'Якщо ви помираєте від страти, ваша команда програє.', 'outsider', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/saint.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('savant', 'Savant', 'Ерудит', 'Each day, you may visit the Storyteller to learn 2 things in private: 1 is true & 1 is false.', 'Щодня ви можете відвідати Оповідача, щоб дізнатись 2 речі приватно: 1 правдива, а 1 хибна.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/savant.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('scapegoat', 'Scapegoat', 'Цап-Відбувайло', 'If a player of your alignment is executed, you might be executed instead.', 'Якщо гравця вашої сторони стратять, вас можуть стратити натомість.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/scapegoat.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('scarletwoman', 'Scarlet Woman', 'Багряна Жінка', 'If there are 5 or more players alive & the Demon dies, you become the Demon. (Travellers don’t count)', 'Якщо живих 5 або більше гравців і Демон помирає, ви стаєте Демоном. (Мандрівники не рахуються)', 'minion', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/scarletwoman.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":20,"otherNightReminder":"If the Scarlet Woman became the Demon today: Show the ''You are'' card, then the demon token.","setup":false,"reminders":["Demon"]}'),
  ('seamstress', 'Seamstress', 'Швачка', 'Once per game, at night, choose 2 players (not yourself): you learn if they are the same alignment.', 'Раз за гру, вночі, оберіть 2 гравців (не себе): ви дізнаєтесь, чи вони однієї сторони.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/seamstress.png', '{"firstNight":47,"firstNightReminder":"The Seamstress either shows a ''no'' head signal, or points to two other players. If the Seamstress chose players , nod ''yes'' or shake ''no'' for whether they are of same alignment.","otherNight":67,"otherNightReminder":"If the Seamstress has not yet used their ability: the Seamstress either shows a ''no'' head signal, or points to two other players. If the Seamstress chose players , nod ''yes'' or shake ''no'' for whether they are of same alignment.","setup":false,"reminders":["No ability"]}'),
  ('sentinel', 'Sentinel', 'Сентінел', 'There might be 1 extra or 1 fewer Outsider in play.', 'У грі може бути на 1 Аутсайдера більше або менше.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/sentinel.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":true,"reminders":[]}'),
  ('shabaloth', 'Shabaloth', 'Шабалот', 'Each night*, choose 2 players: they die. A dead player you chose last night might be regurgitated.', 'Щоночі* оберіть 2 гравців: вони помирають. Мертвий гравець, якого ви обрали минулої ночі, може воскреснути.', 'demon', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/shabaloth.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":29,"otherNightReminder":"One player that the Shabaloth chose the previous night might be resurrected. The Shabaloth points to two players. Those players die.","setup":false,"reminders":["Dead","Alive"]}'),
  ('shugenja', 'Shugenja', 'Шугенджа', 'You start knowing if your closest evil player is clockwise or anti-clockwise. If equidistant, this info is arbitrary.', 'На початку ви дізнаєтесь, чи ваш найближчий злий гравець за годинниковою стрілкою чи проти. Якщо рівновіддалені, ця інформація довільна.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/shugenja.png', '{"firstNight":52,"firstNightReminder":"Wake the Shugenja; point horizontally in the direction of the closest evil player. If the two closest evil players are equidistant, point your finger horizontally in either direction.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('slayer', 'Slayer', 'Вбивця', 'Once per game, during the day, publicly choose a player: if they are the Demon, they die.', 'Раз за гру, вдень, публічно оберіть гравця: якщо він Демон, він помирає.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/slayer.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('snakecharmer', 'Snake Charmer', 'Заклинач Змій', 'Each night, choose an alive player: a chosen Demon swaps characters & alignments with you & is then poisoned.', 'Щоночі оберіть живого гравця: обраний Демон обмінюється персонажами та сторонами з вами і потім отруєний.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/snakecharmer.png', '{"firstNight":23,"firstNightReminder":"The Snake Charmer points to a player. If that player is the Demon: swap the Demon and Snake Charmer character and alignments. Wake each player to inform them of their new role and alignment. The new Snake Charmer is poisoned.","otherNight":11,"otherNightReminder":"The Snake Charmer points to a player. If that player is the Demon: swap the Demon and Snake Charmer character and alignments. Wake each player to inform them of their new role and alignment. The new Snake Charmer is poisoned.","setup":false,"reminders":["Poisoned"]}'),
  ('snitch', 'Snitch', 'Стукач', 'Minions start knowing 3 not-in-play characters.', 'На початку Міньйони дізнаються 3 персонажів, яких немає у грі.', 'outsider', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/snitch.png', '{"firstNight":9,"firstNightReminder":"After Minion info wake each Minion and show them three not-in-play character tokens. These may be the same or different to each other and the ones shown to the Demon.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('soldier', 'Soldier', 'Солдат', 'You are safe from the Demon.', 'Ви захищені від Демона.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/soldier.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('spiritofivory', 'Spirit of Ivory', 'Дух Слонової Кості', 'There can''t be more than 1 extra evil player.', 'Не може бути більше 1 додаткового злого гравця.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/spiritofivory.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No extra evil"]}'),
  ('spy', 'Spy', 'Шпигун', 'Each night, you see the Grimoire. You might register as good & as a Townsfolk or Outsider, even if dead.', 'Щоночі ви бачите Гримуар. Ви можете реєструватися як добрий та як Городянин або Аутсайдер, навіть якщо мертві.', 'minion', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/spy.png', '{"firstNight":57,"firstNightReminder":"Show the Grimoire to the Spy for as long as they need.","otherNight":76,"otherNightReminder":"Show the Grimoire to the Spy for as long as they need.","setup":false,"reminders":[]}'),
  ('steward', 'Steward', 'Управитель', 'You start knowing 1 good player.', 'На початку ви дізнаєтесь 1 доброго гравця.', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/steward.png', '{"firstNight":48,"firstNightReminder":"Point to a good player.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Knows"]}'),
  ('stormcatcher', 'Storm Catcher', 'Ловець Бурі', 'Name a good character. If in play, they can only die by execution, but evil players learn which player it is.', 'Назвіть доброго персонажа. Якщо він у грі, він може померти лише від страти, але злі гравці дізнаються, який це гравець.', 'fabled', 'ks', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/stormcatcher.png', '{"firstNight":null,"firstNightReminder":"Mark a good player as \"Safe\". Wake each evil player and show them the marked player.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Safe"]}'),
  ('summoner', 'Summoner', 'Призивач', 'You get 3 bluffs. On the 3rd night, choose a player: they become an evil Demon of your choice. [No Demon]', 'Ви отримуєте 3 блефи. На 3-ю ніч оберіть гравця: він стає злим Демоном на ваш вибір. [No Demon]', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/summoner.png', '{"firstNight":11,"firstNightReminder":"Show the ''These characters are not in play'' card. Show 3 character tokens of good characters not in play.","otherNight":21,"otherNightReminder":"If it is the 3rd night, wake the Summoner. They point to a player and a Demon on the character sheet - that player becomes that Demon.","setup":true,"reminders":["Night 1","Night 2","Night 3"]}'),
  ('sweetheart', 'Sweetheart', 'Коханий', 'When you die, 1 player is drunk from now on.', 'Коли ви помираєте, 1 гравець стає п''яним відтепер.', 'outsider', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/sweetheart.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":47,"otherNightReminder":"Choose a player that is drunk.","setup":false,"reminders":["Drunk"]}'),
  ('tealady', 'Tea Lady', 'Чайна Леді', 'If both your alive neighbours are good, they can''t die.', 'Якщо обидва ваших живих сусіди добрі, вони не можуть померти.', 'townsfolk', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/tealady.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Can not die"]}'),
  ('thief', 'Thief', 'Злодій', 'Each night, choose a player (not yourself): their vote counts negatively tomorrow.', 'Щоночі оберіть гравця (не себе): його голос завтра рахується негативно.', 'traveller', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/thief.png', '{"firstNight":null,"firstNightReminder":"The Thief points to a player. Put the Thief''s ''Negative vote'' reminder by the chosen player''s character token.","otherNight":null,"otherNightReminder":"The Thief points to a player. Put the Thief''s ''Negative vote'' reminder by the chosen player''s character token.","setup":false,"reminders":["Negative vote"]}'),
  ('tinker', 'Tinker', 'Ремісник', 'You might die at any time.', 'Ви можете померти будь-коли.', 'outsider', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/tinker.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":56,"otherNightReminder":"The Tinker might die.","setup":false,"reminders":["Dead"]}'),
  ('towncrier', 'Town Crier', 'Глашатай', 'Each night*, you learn if a Minion nominated today.', 'Щоночі* ви дізнаєтесь, чи номінував Міньйон сьогодні.', 'townsfolk', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/towncrier.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":65,"otherNightReminder":"Nod ''yes'' or shake head ''no'' for whether a Minion nominated today. Place the ''Minion not nominated'' marker (remove ''Minion nominated'', if any).","setup":false,"reminders":["Minions not nominated","Minion nominated"]}'),
  ('toymaker', 'Toymaker', 'Іграшкар', 'The Demon may choose not to attack & must do this at least once per game. Evil players get normal starting info.', 'Демон може не атакувати і повинен зробити це щонайменше раз за гру. Злі гравці отримують звичайну початкову інформацію.', 'fabled', 'base3', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/toymaker.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":"If it is a night when a Demon attack could end the game, and the Demon is marked “Final night: No Attack,” then the Demon does not act tonight. (Do not wake them.)","setup":false,"reminders":["Final Night: No Attack"]}'),
  ('undertaker', 'Undertaker', 'Гробар', 'Each night*, you learn which character died by execution today.', 'Щоночі* ви дізнаєтесь, який персонаж був страчений сьогодні.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/undertaker.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":62,"otherNightReminder":"If a player was executed today: Show that player’s character token.","setup":false,"reminders":["Executed"]}'),
  ('vigormortis', 'Vigormortis', 'Вігор Мортіс', 'Each night*, choose a player: they die. Minions you kill keep their ability & poison 1 Townsfolk neighbour. [−1 Outsider]', 'Щоночі* оберіть гравця: він помирає. Міньйони, яких ви вбиваєте, зберігають свою здатність та отруюють 1 сусіда-Городянина. [-1 Outsider]', 'demon', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/vigormortis.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":34,"otherNightReminder":"The Vigormortis points to a player. That player dies. If a Minion, they keep their ability and one of their Townsfolk neighbours is poisoned.","setup":true,"reminders":["Dead","Has ability","Poisoned"]}'),
  ('villageidiot', 'Village Idiot', 'Сільський Дурник', 'Each night, choose a player: you learn their alignment. [+0 to +2 Village Idiots. 1 of the extras is drunk]', 'Щоночі оберіть гравця: ви дізнаєтесь його сторону. [+0 to +2 Village Idiots. 1 of the extras is drunk]', 'townsfolk', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/villageidiot.png', '{"firstNight":53,"firstNightReminder":"The Village Idiot points to a player; give a thumbs up if that player is good or a thumbs down if that player is evil.","otherNight":70,"otherNightReminder":"The Village Idiot points to a player; give a thumbs up if that player is good or a thumbs down if that player is evil.","setup":true,"reminders":["Drunk"]}'),
  ('virgin', 'Virgin', 'Діва', 'The 1st time you are nominated, if the nominator is a Townsfolk, they are executed immediately.', '1-й раз, коли вас номінують, якщо номінатор — Городянин, його негайно стратять.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/virgin.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["No ability"]}'),
  ('vizier', 'Vizier', 'Візир', 'All players know who you are. You can not die during the day. If good voted, you may choose to execute immediately.', 'Всі гравці знають, хто ви. Ви не можете померти вдень. Якщо добро голосувало, ви можете обрати негайну страту.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/vizier.png', '{"firstNight":65,"firstNightReminder":"Announce ''The Vizier is in play'' and state which player they are.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('vortox', 'Vortox', 'Вортокс', 'Each night*, choose a player: they die. Townsfolk abilities yield false info. Each day, if no-one is executed, evil wins.', 'Щоночі* оберіть гравця: він помирає. Здатності Городян дають хибну інформацію. Щодня, якщо нікого не стратять, зло перемагає.', 'demon', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/vortox.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":33,"otherNightReminder":"The Vortox points to a player. That player dies.","setup":false,"reminders":["Dead"]}'),
  ('voudon', 'Voudon', 'Вуду', 'Only you and the dead can vote. They don''t need a vote token to do so. A 50% majority is not required.', 'Тільки ви та мертві можете голосувати. Їм не потрібен жетон голосу для цього. Більшість у 50% не потрібна.', 'traveller', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/voudon.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":null,"otherNightReminder":null,"setup":false,"reminders":[]}'),
  ('washerwoman', 'Washerwoman', 'Прачка', 'You start knowing that 1 of 2 players is a particular Townsfolk.', 'На початку ви дізнаєтесь, що 1 з 2 гравців є певним Городянином.', 'townsfolk', 'tb', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/washerwoman.png', '{"firstNight":37,"firstNightReminder":"Show the character token of a Townsfolk in play. Point to two players, one of which is that character.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Townsfolk","Wrong"]}'),
  ('widow', 'Widow', 'Вдова', 'On your 1st night, look at the Grimoire and choose a player: they are poisoned. 1 good player knows a Widow is in play.', 'У вашу 1-шу ніч подивіться на Гримуар та оберіть гравця: він отруєний. 1 добрий гравець знає, що Вдова у грі.', 'minion', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/widow.png', '{"firstNight":21,"firstNightReminder":"Show the Grimoire to the Widow for as long as they need. The Widow points to a player. That player is poisoned. Wake a good player. Show the ''These characters are in play'' card, then the Widow character token.","otherNight":null,"otherNightReminder":null,"setup":false,"reminders":["Poisoned"]}'),
  ('witch', 'Witch', 'Відьма', 'Each night, choose a player: if they nominate tomorrow, they die. If just 3 players live, you lose this ability.', 'Щоночі оберіть гравця: якщо він номінує завтра, він помирає. Якщо залишилось лише 3 живих гравці, ви втрачаєте цю здатність.', 'minion', 'snv', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/witch.png', '{"firstNight":27,"firstNightReminder":"The Witch points to a player. If that player nominates tomorrow they die immediately.","otherNight":14,"otherNightReminder":"If there are 4 or more players alive: The Witch points to a player. If that player nominates tomorrow they die immediately.","setup":false,"reminders":["Cursed"]}'),
  ('yaggababble', 'Yaggababble', 'Яґґабаббл', 'You start knowing a secret phrase. For each time you said it publicly today, a player might die.', 'На початку ви дізнаєтесь таємну фразу. За кожен раз, коли ви сказали її публічно сьогодні, гравець може померти.', 'demon', 'experimental', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/yaggababble.png', '{"firstNight":6,"firstNightReminder":"Show the Yaggababble their secret phrase.","otherNight":39,"otherNightReminder":"Choose a number of players up to the total number of times the Yaggababble said their secret phrase publicly, those players die.","setup":false,"reminders":["Dead"]}'),
  ('zombuul', 'Zombuul', 'Зомбуул', 'Each night*, if no-one died today, choose a player: they die. The 1st time you die, you live but register as dead.', 'Щоночі*, якщо сьогодні ніхто не помер, оберіть гравця: він помирає. 1-й раз, коли ви помираєте, ви виживаєте, але реєструєтесь як мертвий.', 'demon', 'bmr', 'https://raw.githubusercontent.com/chizmw/json-on-the-clocktower/main/data/images/zombuul.png', '{"firstNight":null,"firstNightReminder":null,"otherNight":27,"otherNightReminder":"If no-one died during the day: The Zombuul points to a player. That player dies.","setup":false,"reminders":["Died today","Dead"]}')
